<script>
const subMap=@json($subMap ?? []),selectedSub=@json($selectedSub ?? null),oldAttributes=@json($oldAttributes ?? $attributeValues ?? []),oldUnits=@json($oldUnits ?? $unitValues ?? []),oldVariants=@json($oldVariants ?? $variantValues ?? []);
const productForm=document.getElementById('productForm'),categorySelect=document.getElementById('category_id'),subcategorySelect=document.getElementById('subcategory_id'),hasVariantsToggle=document.getElementById('hasVariantsToggle'),submitProductBtn=document.getElementById('submitProductBtn');
const productModeSimple=document.getElementById('productModeSimple'),productModeVariants=document.getElementById('productModeVariants');
const hasVariantsEnabledInput=document.getElementById('hasVariantsEnabledInput');
const attributesPlaceholder=document.getElementById('attributesPlaceholder'),dynamicAttributesWrap=document.getElementById('dynamicAttributesWrap'),dynamicAttributes=document.getElementById('dynamicAttributes');
const variantConfiguratorWrap=document.getElementById('variantConfiguratorWrap'),variantAttributesSelectors=document.getElementById('variantAttributesSelectors'),generateVariantsBtn=document.getElementById('generateVariantsBtn'),addVariantRowBtn=document.getElementById('addVariantRowBtn'),clearVariantsBtn=document.getElementById('clearVariantsBtn'),variantHelper=document.getElementById('variantHelper');
const variantsTableWrap=document.getElementById('variantsTableWrap'),variantsRows=document.getElementById('variantsRows');
const imageInput=document.getElementById('image'),imagePreviewWrap=document.getElementById('imagePreviewWrap'),imagePreview=document.getElementById('imagePreview');
const galleryInput=document.getElementById('gallery'),galleryPreviewWrap=document.getElementById('galleryPreviewWrap'),galleryPreviewGrid=document.getElementById('galleryPreviewGrid');
const gallerySelectionNote=document.getElementById('gallerySelectionNote'),gallerySelectionCount=document.getElementById('gallerySelectionCount');
const listingReadinessBadge=document.getElementById('listingReadinessBadge'),listingReadinessText=document.getElementById('listingReadinessText'),listingReadinessList=document.getElementById('listingReadinessList');
const catalogAssistantPanel=document.getElementById('catalogAssistantPanel'),catalogAssistantTitle=document.getElementById('catalogAssistantTitle'),catalogAssistantText=document.getElementById('catalogAssistantText'),catalogAssistantList=document.getElementById('catalogAssistantList');
const GALLERY_LIMIT=8,MAX_GENERATED_VARIANTS=60; let currentAttributes=[],currentVariantAttributes=[],selectedGalleryFiles=[];
const escapeHtml=value=>String(value??'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#039;');
const cartesian=arrays=>!arrays.length?[]:arrays.reduce((acc,curr)=>acc.flatMap(a=>curr.map(b=>[].concat(a,[b]))),[[]]);
const renderMessageList=(target,items)=>{ if(!target)return; target.innerHTML=(items||[]).map(item=>`<li>${escapeHtml(item)}</li>`).join(''); };
function setAssistantState(tone,title,text,items=[]){ if(!catalogAssistantPanel)return; const styles={info:['border-blue-100','bg-blue-50','text-blue-900','text-blue-800'],warning:['border-amber-200','bg-amber-50','text-amber-900','text-amber-800'],success:['border-emerald-200','bg-emerald-50','text-emerald-900','text-emerald-800'],danger:['border-red-200','bg-red-50','text-red-900','text-red-800']}; const style=styles[tone]||styles.info; catalogAssistantPanel.classList.remove('hidden','border-blue-100','bg-blue-50','border-amber-200','bg-amber-50','border-emerald-200','bg-emerald-50','border-red-200','bg-red-50'); catalogAssistantPanel.classList.add(style[0],style[1]); catalogAssistantTitle.className=`text-sm font-semibold ${style[2]}`; catalogAssistantText.className=`mt-2 text-sm ${style[3]}`; catalogAssistantList.className=`mt-3 space-y-2 text-xs ${style[3]}`; catalogAssistantTitle.textContent=title; catalogAssistantText.textContent=text; renderMessageList(catalogAssistantList,items); }
function setVariantHelper(text,tone='info'){ if(!variantHelper)return; variantHelper.className='mt-4 rounded-2xl border px-4 py-3 text-sm'; const styles={info:['border-blue-200','bg-blue-50','text-blue-900'],warning:['border-amber-200','bg-white/80','text-amber-900'],success:['border-emerald-200','bg-emerald-50','text-emerald-900'],danger:['border-red-200','bg-red-50','text-red-900']}; variantHelper.classList.add(...(styles[tone]||styles.info)); variantHelper.textContent=text; }
function updateReadinessPanel(missing=[],warnings=[]){ if(!listingReadinessBadge)return; if(missing.length){ listingReadinessBadge.textContent='Necesita atentie'; listingReadinessBadge.className='rounded-full bg-white px-3 py-1 text-[11px] font-semibold text-red-700'; listingReadinessText.textContent='Mai sunt cateva lucruri importante de completat inainte de publicare.'; renderMessageList(listingReadinessList,missing.concat(warnings).slice(0,6)); return; } if(warnings.length){ listingReadinessBadge.textContent='Aproape gata'; listingReadinessBadge.className='rounded-full bg-white px-3 py-1 text-[11px] font-semibold text-amber-700'; listingReadinessText.textContent='Produsul poate fi salvat, dar cateva detalii il fac mai clar pentru clienti.'; renderMessageList(listingReadinessList,warnings.slice(0,6)); return; } listingReadinessBadge.textContent='Gata de publicare'; listingReadinessBadge.className='rounded-full bg-white px-3 py-1 text-[11px] font-semibold text-emerald-700'; listingReadinessText.textContent='Produsul arata complet pentru seller, filtre si afisare.'; renderMessageList(listingReadinessList,['Categoria finala este selectata.','Atributele principale sunt completate.','Imaginile si pretul sunt pregatite.']); }
function getGalleryFileKey(file){ return `${file.name}::${file.size}::${file.lastModified}`; }
function syncGalleryInputFiles(){ if(!galleryInput) return; const transfer=new DataTransfer(); selectedGalleryFiles.forEach(file=>transfer.items.add(file)); galleryInput.files=transfer.files; }
function updateGallerySelectionText(message=''){ if(gallerySelectionCount) gallerySelectionCount.textContent=`${selectedGalleryFiles.length}/${GALLERY_LIMIT} imagini selectate`; if(gallerySelectionNote) gallerySelectionNote.textContent=message||(!selectedGalleryFiles.length?'Poti adauga pozele pe rand. Fiecare selectie noua se adauga la cele deja alese.':'Poti reveni cu alte poze oricand. Lista curenta ramane pana scoti manual o imagine.'); }
function renderGalleryPreview(){ if(!galleryPreviewGrid||!galleryPreviewWrap) return; galleryPreviewGrid.innerHTML=''; if(!selectedGalleryFiles.length){ galleryPreviewWrap.classList.add('hidden'); updateGallerySelectionText(); return; } selectedGalleryFiles.forEach((file,index)=>{ const reader=new FileReader(); reader.onload=readerEvent=>{ const card=document.createElement('div'); card.className='overflow-hidden rounded-2xl border border-gray-200 bg-white shadow-sm'; card.innerHTML=`<img src="${readerEvent.target.result}" class="h-32 w-full object-cover" alt="Preview"><div class="flex items-center justify-between gap-3 px-3 py-3"><div class="min-w-0"><div class="truncate text-xs font-medium text-gray-900">${escapeHtml(file.name)}</div><div class="mt-1 text-[11px] text-gray-500">${Math.max(1,Math.round(file.size/1024))} KB</div></div><button type="button" class="remove-gallery-file rounded-xl border border-red-300 px-3 py-2 text-xs font-semibold text-red-600 hover:bg-red-50" data-gallery-index="${index}">Scoate</button></div>`; galleryPreviewGrid.appendChild(card); }; reader.readAsDataURL(file); }); galleryPreviewWrap.classList.remove('hidden'); updateGallerySelectionText(); }
function removeGalleryFile(index){ selectedGalleryFiles=selectedGalleryFiles.filter((_,fileIndex)=>fileIndex!==index); syncGalleryInputFiles(); renderGalleryPreview(); }
function mergeGalleryFiles(newFiles=[]){ const merged=[...selectedGalleryFiles],seen=new Set(merged.map(getGalleryFileKey)); let skippedCount=0; newFiles.forEach(file=>{ const key=getGalleryFileKey(file); if(seen.has(key)||merged.length>=GALLERY_LIMIT){ skippedCount++; return; } merged.push(file); seen.add(key); }); selectedGalleryFiles=merged; syncGalleryInputFiles(); renderGalleryPreview(); if(skippedCount>0) updateGallerySelectionText(`Au fost pastrate doar imaginile noi care intra in limita de ${GALLERY_LIMIT} si nu sunt duplicate.`); }
function refreshSubcategories(selectedValue=null){ const categoryId=categorySelect.value; subcategorySelect.innerHTML='<option value="">- alege categoria finala -</option>'; if(!categoryId||!subMap[categoryId]||!subMap[categoryId].length){ subcategorySelect.disabled=true; return; } subcategorySelect.disabled=false; subMap[categoryId].forEach(item=>{ const option=document.createElement('option'); option.value=item.id; option.textContent=item.name; if(selectedValue&&String(selectedValue)===String(item.id)) option.selected=true; subcategorySelect.appendChild(option); }); }
const getOldValue=id=>oldAttributes?.[id]??oldAttributes?.[String(id)]??null; const getOldUnit=(id,attr)=>(oldUnits?.[id]??oldUnits?.[String(id)]??attr.default_unit??'');
function getPrimaryVariantAttribute(){ return currentVariantAttributes.find(attr=>String(attr.name||'').toLowerCase().includes('culo')||String(attr.name||'').toLowerCase().includes('color'))||currentVariantAttributes[0]||null; }
const getSecondaryVariantAttributes=()=>{ const primary=getPrimaryVariantAttribute(); return currentVariantAttributes.filter(attr=>String(attr.id)!==String(primary?.id)); };
const getRequiredNonVariantAttributes=()=>currentAttributes.filter(attr=>!attr.is_variant&&!!attr.is_required);
const getBrandAttribute=()=>currentAttributes.find(attr=>!attr.is_variant&&String(attr.slug||'').toLowerCase()==='brand')||null;
function getAttributeInput(attributeId,attrType){ if(attrType==='multiselect') return document.querySelector(`select[name="attributes[${attributeId}][]"]`); if(attrType==='boolean') return document.querySelector(`input[type="checkbox"][name="attributes[${attributeId}]"]`); return document.querySelector(`[name="attributes[${attributeId}]"]`); }
function getCurrentAttributeValue(attr){ const input=getAttributeInput(attr.id,attr.type); if(!input) return null; if(attr.type==='multiselect') return Array.from(input.selectedOptions||[]).map(option=>option.value).filter(Boolean); if(attr.type==='boolean') return input.checked?'1':'0'; return input.value; }
function isFilledValue(attr,value){ if(attr.type==='multiselect') return Array.isArray(value)&&value.filter(item=>item!==null&&item!=='').length>0; if(attr.type==='boolean') return true; return !(value===null||value===''); }
function buildVariantLabel(attributes){ return attributes.map(item=>`${item.attribute_name}: ${item.custom_value&&item.custom_value!==''?item.custom_value:item.option_label}`).join(' / '); }
function buildVariantKeyFromMeta(attrsMeta=[]){ return attrsMeta.map(item=>`${item.attribute_id}:${item.is_custom?`custom:${item.custom_value}`:`opt:${item.option_id}`}`).sort().join('|'); }
const getExistingVariantKeys=()=>Array.from(variantsRows.querySelectorAll('[data-variant-card]')).map(card=>card.dataset.variantKey||'').filter(Boolean);
function variantCardHtml(index,variant={}){ const attrs=Array.isArray(variant.attributes_meta)?variant.attributes_meta:[]; const label=attrs.length?buildVariantLabel(attrs):`Varianta ${index+1}`; let hiddenInputs=''; attrs.forEach(item=>{ hiddenInputs+=item.is_custom?`<input type="hidden" name="variants[${index}][attributes][${item.attribute_id}][custom_value]" value="${escapeHtml(item.custom_value)}">`:`<input type="hidden" name="variants[${index}][attributes][${item.attribute_id}][option_id]" value="${escapeHtml(item.option_id)}">`; }); return `<div class="rounded-3xl border border-gray-200 bg-white p-5 shadow-sm"><div class="mb-4 flex items-start justify-between gap-4"><div><div class="text-sm font-semibold text-gray-900">${escapeHtml(label)}</div><div class="mt-1 text-xs text-gray-500">Completeaza datele pentru aceasta varianta.</div></div><button type="button" class="remove-variant-btn rounded-xl border border-red-300 px-3 py-2 text-xs font-semibold text-red-600 hover:bg-red-50">Sterge</button></div>${hiddenInputs}<div class="grid grid-cols-1 gap-4 md:grid-cols-4"><div><label class="mb-2 block text-xs font-medium text-gray-600">SKU</label><input type="text" name="variants[${index}][sku]" value="${escapeHtml(variant.sku??'')}" class="w-full rounded-2xl border border-gray-300 px-4 py-3 text-sm"></div><div><label class="mb-2 block text-xs font-medium text-gray-600">Pret</label><input type="number" step="0.01" min="0" name="variants[${index}][price]" value="${escapeHtml(variant.price??'')}" class="w-full rounded-2xl border border-gray-300 px-4 py-3 text-sm variant-price-input"></div><div><label class="mb-2 block text-xs font-medium text-gray-600">Stoc</label><input type="number" min="0" name="variants[${index}][stock]" value="${escapeHtml(variant.stock??'')}" class="w-full rounded-2xl border border-gray-300 px-4 py-3 text-sm variant-stock-input"></div><div><label class="mb-2 block text-xs font-medium text-gray-600">Imagine varianta</label><input type="file" accept="image/*" name="variants[${index}][image]" class="block w-full text-sm text-gray-700"></div></div><div class="mt-4"><label class="inline-flex items-center gap-3 text-sm text-gray-700"><input type="hidden" name="variants[${index}][is_active]" value="0"><input type="checkbox" name="variants[${index}][is_active]" value="1" ${(variant.is_active===0||variant.is_active==='0')?'':'checked'} class="rounded border-gray-300"><span>Varianta activa</span></label></div></div>`; }
function reindexVariantCards(){ const cards=Array.from(variantsRows.querySelectorAll('[data-variant-card]')); cards.forEach((card,index)=>{ const oldIndex=card.dataset.variantCard; card.dataset.variantCard=index; card.querySelectorAll('[name]').forEach(el=>{ el.name=el.name.replace(new RegExp(`variants\\[${oldIndex}\\]`,'g'),`variants[${index}]`); }); }); variantsTableWrap.classList.toggle('hidden',cards.length===0); }
function toggleBaseStock(){ const hasVariants=variantsRows.children.length>0,baseStockWrap=document.getElementById('baseStockWrap'); if(baseStockWrap) baseStockWrap.style.display=hasVariants?'none':'block'; }
function updateTotalStockFromVariants(){ const baseStockInput=document.querySelector('input[name="stock"]'),stockInputs=Array.from(document.querySelectorAll('.variant-stock-input')); if(!baseStockInput) return; if(!stockInputs.length){ baseStockInput.readOnly=false; return; } baseStockInput.value=stockInputs.reduce((sum,input)=>sum+(parseInt(input.value||'0',10)||0),0); baseStockInput.readOnly=true; }
const isVariantsMode=()=>!!(productModeVariants?.checked||hasVariantsToggle?.checked);
function updateVariantModeUI(){
    const enabled=isVariantsMode();
    if(hasVariantsToggle) hasVariantsToggle.checked=enabled;
    if(variantConfiguratorWrap) variantConfiguratorWrap.classList.toggle('hidden',!enabled||!currentVariantAttributes.length);
    if(variantsTableWrap) variantsTableWrap.classList.toggle('hidden',!enabled||variantsRows.children.length===0);
}
function syncVariantControls(){ const enabled=hasVariantsToggle?hasVariantsToggle.checked:true; [generateVariantsBtn,addVariantRowBtn,clearVariantsBtn,...Array.from(variantAttributesSelectors.querySelectorAll('input, button'))].filter(Boolean).forEach(control=>control.disabled=!enabled); variantAttributesSelectors.classList.toggle('pointer-events-none',!enabled); variantAttributesSelectors.classList.toggle('opacity-60',!enabled); if(!enabled) setVariantHelper('Varianta este oprita. Activeaz-o doar daca produsul are combinatii reale pentru client.','warning'); else if(!variantsRows.children.length) setVariantHelper('Alege valorile importante ale produsului, apoi genereaza combinatiile sau adauga manual o varianta.','info'); }
function syncVariantsIntent(){ if(hasVariantsEnabledInput){ hasVariantsEnabledInput.value=(hasVariantsToggle?hasVariantsToggle.checked:(variantsRows.children.length>0))?'1':'0'; } }
function syncProductModeFromToggle(){ if(!hasVariantsToggle) return; if(productModeVariants) productModeVariants.checked=!!hasVariantsToggle.checked; if(productModeSimple) productModeSimple.checked=!hasVariantsToggle.checked; }
function appendVariantCard(variant={}){ const index=variantsRows.querySelectorAll('[data-variant-card]').length,wrapper=document.createElement('div'),attrsMeta=Array.isArray(variant.attributes_meta)?variant.attributes_meta:[],variantKey=buildVariantKeyFromMeta(attrsMeta); wrapper.dataset.variantCard=index; wrapper.dataset.variantKey=variantKey; wrapper.dataset.variantMeta=JSON.stringify(attrsMeta); wrapper.innerHTML=variantCardHtml(index,variant); variantsRows.appendChild(wrapper); updateVariantModeUI(); syncVariantsIntent(); toggleBaseStock(); updateTotalStockFromVariants(); syncVariantControls(); updateFormGuidance(); }
function loadSizesForSelectedColor(){ const primaryAttr=getPrimaryVariantAttribute(),secondaryAttrs=getSecondaryVariantAttributes(); if(!primaryAttr||!secondaryAttrs.length) return; const selectedPrimary=document.querySelector(`input[name="variant_attr_${primaryAttr.id}"]:checked`); secondaryAttrs.forEach(attr=>document.querySelectorAll(`.variant-checkbox[data-attribute-id="${attr.id}"]`).forEach(cb=>cb.checked=false)); if(!selectedPrimary) return; const selectedPrimaryValue=selectedPrimary.dataset.custom==='1'?`custom:${selectedPrimary.dataset.label}`:`opt:${selectedPrimary.dataset.optionId}`; Array.from(variantsRows.querySelectorAll('[data-variant-card]')).forEach(card=>{ let meta=[]; try{ meta=JSON.parse(card.dataset.variantMeta||'[]'); }catch(error){ meta=[]; } const primaryMatch=meta.find(item=>String(item.attribute_id)===String(primaryAttr.id)&&(item.is_custom?`custom:${item.custom_value}`:`opt:${item.option_id}`)===selectedPrimaryValue); if(!primaryMatch) return; secondaryAttrs.forEach(attr=>{ const secondaryMatch=meta.find(item=>String(item.attribute_id)===String(attr.id)); if(!secondaryMatch) return; const selector=secondaryMatch.is_custom?`.variant-checkbox[data-attribute-id="${attr.id}"][data-custom="1"][data-label="${CSS.escape(secondaryMatch.custom_value)}"]`:`.variant-checkbox[data-attribute-id="${attr.id}"][data-custom="0"][data-option-id="${secondaryMatch.option_id}"]`; const input=document.querySelector(selector); if(input) input.checked=true; }); }); }
function renderAttributeField(attr){ if(attr.is_variant) return ''; const value=getOldValue(attr.id),unitValue=getOldUnit(attr.id,attr),requiredMark=attr.is_required?'<span class="text-red-500"> *</span>':''; let html=`<div class="rounded-2xl border border-gray-200 bg-gray-50 p-4" data-attribute-card="${attr.id}"><label class="mb-2 block text-sm font-medium text-gray-700">${escapeHtml(attr.name)}${requiredMark}</label>`; if(attr.type==='select'){ html+=`<select name="attributes[${attr.id}]" class="w-full rounded-2xl border border-gray-300 bg-white px-4 py-3 text-sm"><option value="">- selecteaza -</option>${(attr.options||[]).map(opt=>`<option value="${opt.id}" ${String(value??'')===String(opt.id)?'selected':''}>${escapeHtml(opt.label)}</option>`).join('')}</select>`; } else if(attr.type==='multiselect'){ const values=Array.isArray(value)?value.map(String):[]; html+=`<select name="attributes[${attr.id}][]" multiple class="min-h-[130px] w-full rounded-2xl border border-gray-300 bg-white px-4 py-3 text-sm">${(attr.options||[]).map(opt=>`<option value="${opt.id}" ${values.includes(String(opt.id))?'selected':''}>${escapeHtml(opt.label)}</option>`).join('')}</select>`; } else if(attr.type==='boolean'){ html+=`<label class="inline-flex items-center gap-3"><input type="hidden" name="attributes[${attr.id}]" value="0"><input type="checkbox" name="attributes[${attr.id}]" value="1" ${String(value??'')==='1'?'checked':''} class="rounded border-gray-300"><span class="text-sm text-gray-700">Da</span></label>`; } else if(attr.type==='number'){ html+='<div class="flex gap-2">'; html+=`<input type="number" step="0.01" name="attributes[${attr.id}]" value="${escapeHtml(value??'')}" class="w-full rounded-2xl border border-gray-300 bg-white px-4 py-3 text-sm">`; if(attr.unit_mode==='fixed'&&attr.default_unit){ html+=`<input type="hidden" name="units[${attr.id}]" value="${escapeHtml(attr.default_unit)}"><div class="rounded-2xl border border-gray-300 bg-white px-4 py-3 text-sm text-gray-700">${escapeHtml(attr.default_unit)}</div>`; } else if(attr.unit_mode==='selectable'&&Array.isArray(attr.allowed_units)&&attr.allowed_units.length){ html+=`<select name="units[${attr.id}]" class="rounded-2xl border border-gray-300 bg-white px-4 py-3 text-sm">${attr.allowed_units.map(unit=>`<option value="${escapeHtml(unit)}" ${String(unitValue)===String(unit)?'selected':''}>${escapeHtml(unit)}</option>`).join('')}</select>`; } else if(attr.unit_mode==='free'){ html+=`<input type="text" name="units[${attr.id}]" value="${escapeHtml(unitValue)}" placeholder="unitate" class="w-28 rounded-2xl border border-gray-300 bg-white px-4 py-3 text-sm">`; } html+='</div>'; } else if(attr.type==='textarea'){ html+=`<textarea name="attributes[${attr.id}]" rows="4" class="w-full rounded-2xl border border-gray-300 bg-white px-4 py-3 text-sm">${escapeHtml(value??'')}</textarea>`; } else { html+=`<input type="text" name="attributes[${attr.id}]" value="${escapeHtml(value??'')}" class="w-full rounded-2xl border border-gray-300 bg-white px-4 py-3 text-sm">`; } return `${html}</div>`; }
function renderVariantAttributeSelector(attr){ const primaryAttr=getPrimaryVariantAttribute(),isPrimary=primaryAttr&&String(primaryAttr.id)===String(attr.id),selectedValues=new Set(); if(Array.isArray(oldVariants)){ oldVariants.forEach(variant=>{ if(!variant.attributes) return; const value=variant.attributes[attr.id]; if(!value) return; selectedValues.add(typeof value==='object'&&value.custom_value?`custom:${value.custom_value}`:`opt:${value}`); }); } return `<div class="rounded-2xl border border-amber-200 bg-white p-4" data-variant-attribute-block="${attr.id}"><label class="mb-3 block text-sm font-medium text-gray-700">${escapeHtml(attr.name)} ${isPrimary?'<span class="text-xs text-gray-400">(alege valoarea principala)</span>':''}</label><div class="variant-checkbox-list flex flex-wrap gap-2">${(attr.options||[]).map(opt=>`<label class="inline-flex items-center gap-2 rounded-xl border border-gray-300 px-3 py-2 text-sm text-gray-700 hover:bg-gray-50"><input type="${isPrimary?'radio':'checkbox'}" name="variant_attr_${attr.id}" class="variant-checkbox" data-attribute-id="${attr.id}" data-option-id="${opt.id}" data-label="${escapeHtml(opt.label)}" data-custom="0" ${selectedValues.has(`opt:${opt.id}`)?'checked':''}><span>${escapeHtml(opt.label)}</span></label>`).join('')}</div><div class="mt-4 flex gap-2"><input type="text" class="custom-variant-input w-full rounded-xl border border-gray-300 px-3 py-2 text-sm" placeholder="Adauga valoare noua, ex: Yellow"><button type="button" class="add-custom-variant rounded-xl bg-gray-900 px-4 py-2 text-sm font-semibold text-white hover:bg-black" data-attribute-id="${attr.id}">Adauga</button></div></div>`; }
function renderAttributeSections(attrs){ currentAttributes=Array.isArray(attrs)?attrs:[]; currentVariantAttributes=currentAttributes.filter(attr=>!!attr.is_variant); const nonVariantAttrs=currentAttributes.filter(attr=>!attr.is_variant); if(!currentAttributes.length){ attributesPlaceholder.classList.remove('hidden'); dynamicAttributesWrap.classList.add('hidden'); variantConfiguratorWrap.classList.add('hidden'); variantsTableWrap.classList.add('hidden'); dynamicAttributes.innerHTML=''; variantAttributesSelectors.innerHTML=''; variantsRows.innerHTML=''; toggleBaseStock(); updateTotalStockFromVariants(); updateFormGuidance(); return; } attributesPlaceholder.classList.add('hidden'); if(nonVariantAttrs.length){ dynamicAttributesWrap.classList.remove('hidden'); dynamicAttributes.innerHTML=nonVariantAttrs.map(renderAttributeField).join(''); } else { dynamicAttributesWrap.classList.add('hidden'); dynamicAttributes.innerHTML=''; } if(currentVariantAttributes.length){ variantAttributesSelectors.innerHTML=currentVariantAttributes.map(renderVariantAttributeSelector).join(''); } else { variantAttributesSelectors.innerHTML=''; variantsRows.innerHTML=''; variantsTableWrap.classList.add('hidden'); } updateVariantModeUI(); toggleBaseStock(); updateTotalStockFromVariants(); syncVariantControls(); updateFormGuidance(); }
async function loadCategoryAttributes(){ const subcategoryId=subcategorySelect.value; if(!subcategoryId){ renderAttributeSections([]); return; } attributesPlaceholder.classList.remove('hidden'); attributesPlaceholder.textContent='Se incarca atributele...'; dynamicAttributesWrap.classList.add('hidden'); variantConfiguratorWrap.classList.add('hidden'); variantsRows.innerHTML=''; variantsTableWrap.classList.add('hidden'); try{ const url=`{{ route('seller.categories.attributes', ':id') }}`.replace(':id',subcategoryId); const response=await fetch(url,{headers:{'Accept':'application/json','X-Requested-With':'XMLHttpRequest'}}); if(!response.ok) throw new Error('Nu s-au putut incarca atributele.'); const data=await response.json(); renderAttributeSections(data); if(Array.isArray(oldVariants)&&oldVariants.length){ variantsRows.innerHTML=''; oldVariants.forEach(variant=>{ const attrsMeta=[]; if(variant.attributes){ Object.keys(variant.attributes).forEach(attributeId=>{ const attr=currentVariantAttributes.find(item=>String(item.id)===String(attributeId)); if(!attr) return; const rawValue=variant.attributes[attributeId]; if(rawValue&&typeof rawValue==='object'&&rawValue.custom_value){ attrsMeta.push({attribute_id:attr.id,attribute_name:attr.name,option_id:null,option_label:null,custom_value:rawValue.custom_value,is_custom:true}); return; } const option=(attr.options||[]).find(opt=>String(opt.id)===String(rawValue)); if(!option) return; attrsMeta.push({attribute_id:attr.id,attribute_name:attr.name,option_id:option.id,option_label:option.label,custom_value:null,is_custom:false}); }); } appendVariantCard({sku:variant.sku??'',price:variant.price??'',stock:variant.stock??'',is_active:variant.is_active??1,attributes_meta:attrsMeta}); }); loadSizesForSelectedColor(); oldVariants.length=0; } } catch(error){ console.error(error); attributesPlaceholder.classList.remove('hidden'); attributesPlaceholder.textContent=error.message||'Eroare la incarcarea atributelor.'; setAssistantState('danger','Atribute indisponibile','Categoria a fost selectata, dar a aparut o problema la incarcarea atributelor.',['Reincearca selectarea categoriei finale.','Daca eroarea persista, verifica setarea atributelor in catalog.']); } }
function collectVariantValidation(){ const problems=[],warnings=[],cards=Array.from(variantsRows.querySelectorAll('[data-variant-card]')),seenKeys=new Set(),seenSkus=new Set(); if(!cards.length){ problems.push('Ai activat varianta de produs, dar nu ai nicio combinatie salvata.'); return {problems,warnings}; } cards.forEach((card,index)=>{ const label=card.querySelector('.text-sm.font-semibold')?.textContent?.trim()||`Varianta ${index+1}`,key=card.dataset.variantKey||'',priceInput=card.querySelector('.variant-price-input'),skuInput=card.querySelector('input[name$="[sku]"]'); if(!key) problems.push(`${label}: lipsesc valorile atributelor variantei.`); else if(seenKeys.has(key)) problems.push(`${label}: exista deja o varianta cu aceeasi combinatie.`); else seenKeys.add(key); if(!priceInput?.value) problems.push(`${label}: completeaza pretul variantei.`); const sku=(skuInput?.value||'').trim(); if(!sku) warnings.push(`${label}: poti adauga SKU pentru gestiune mai usoara.`); else { const normalizedSku=sku.toLowerCase(); if(seenSkus.has(normalizedSku)) problems.push(`${label}: SKU-ul este duplicat.`); else seenSkus.add(normalizedSku); } }); return {problems,warnings}; }
function collectFormState(){ const missing=[],warnings=[]; if(!categorySelect.value) missing.push('Selecteaza categoria principala.'); if(!subcategorySelect.value) missing.push('Selecteaza categoria finala pentru a primi atributele corecte.'); const nameInput=productForm?.querySelector('input[name="name"]'); if(!nameInput?.value.trim()) missing.push('Completeaza numele produsului.'); const basePriceInput=productForm?.querySelector('input[name="final_price"]'); if(!basePriceInput?.value) missing.push('Completeaza pretul de baza.'); const hasExistingImage=imageInput?.dataset.hasExistingImage==='1'; if(!hasExistingImage&&!(imageInput?.files?.length)) missing.push('Adauga imaginea principala.'); if((galleryInput?.files?.length||0)>GALLERY_LIMIT) missing.push(`Galeria poate avea maximum ${GALLERY_LIMIT} imagini.`); getRequiredNonVariantAttributes().forEach(attr=>{ const value=getCurrentAttributeValue(attr); if(!isFilledValue(attr,value)) missing.push(`Completeaza atributul obligatoriu "${attr.name}".`); }); const brandAttribute=getBrandAttribute(); if(brandAttribute&&!isFilledValue(brandAttribute,getCurrentAttributeValue(brandAttribute))) warnings.push('Adauga brandul produsului pentru filtre mai bune si pagina dedicata de brand.'); const variantsEnabled=hasVariantsToggle?hasVariantsToggle.checked:variantsRows.children.length>0; if(variantsEnabled){ const variantCheck=collectVariantValidation(); missing.push(...variantCheck.problems); warnings.push(...variantCheck.warnings); } else if(currentVariantAttributes.length){ warnings.push('Categoria permite variante. Activeaza-le doar daca produsul chiar are combinatii diferite pentru client.'); } return {missing,warnings}; }
function updateFormGuidance(){ const {missing,warnings}=collectFormState(); updateReadinessPanel(missing,warnings); if(!subcategorySelect.value){ setAssistantState('info','Alege categoria finala','Categoria finala decide exact ce atribute si filtre primeste produsul.',['Selecteaza subcategoria cea mai apropiata de produs.','Dupa selectare incarcam automat campurile potrivite pentru seller si filtre.']); return; } if(missing.length){ setAssistantState('warning','Mai lipsesc cateva detalii','Formularul te ajuta sa prinzi din timp ce poate bloca publicarea sau filtrarea corecta.',missing.slice(0,4)); return; } if(warnings.length){ setAssistantState('success','Structura este buna','Produsul este aproape gata. Recomandarile de mai jos il fac si mai usor de gasit si comparat.',warnings.slice(0,4)); return; } setAssistantState('success','Produsul arata complet','Ai o structura buna pentru seller, filtrare si afisare catre cumparator.',['Categoria finala si atributele sunt pregatite.','Poti salva cu incredere produsul.']); }
function collectSelectedVariantCombos(){ const primaryAttr=getPrimaryVariantAttribute(); if(!primaryAttr){ return {error:'Categoria nu are atribute de varianta configurate.',combos:[]}; } const selectedPrimary=document.querySelector(`input[name="variant_attr_${primaryAttr.id}"]:checked`); if(!selectedPrimary){ return {error:`Alege mai intai o valoare principala pentru ${primaryAttr.name}.`,combos:[]}; } const primaryValue={attribute_id:primaryAttr.id,attribute_name:primaryAttr.name,option_id:selectedPrimary.dataset.optionId||null,option_label:selectedPrimary.dataset.label,custom_value:selectedPrimary.dataset.custom==='1'?selectedPrimary.dataset.label:null,is_custom:selectedPrimary.dataset.custom==='1'}; const groups=[[primaryValue]]; getSecondaryVariantAttributes().forEach(attr=>{ const checked=Array.from(document.querySelectorAll(`.variant-checkbox[data-attribute-id="${attr.id}"]:checked`)); const values=checked.map(cb=>({attribute_id:attr.id,attribute_name:attr.name,option_id:cb.dataset.optionId||null,option_label:cb.dataset.label,custom_value:cb.dataset.custom==='1'?cb.dataset.label:null,is_custom:cb.dataset.custom==='1'})); if(values.length) groups.push(values); }); return {error:null,combos:cartesian(groups)}; }
function addVariantsByPrimaryAttribute(){ const selection=collectSelectedVariantCombos(); if(selection.error){ setVariantHelper(selection.error,'danger'); return; } const combinations=selection.combos; if(!combinations.length){ setVariantHelper('Selecteaza cel putin o combinatie valida de atribute.','danger'); return; } if(combinations.length>MAX_GENERATED_VARIANTS){ setVariantHelper(`Ai selectat prea multe combinatii (${combinations.length}). Redu valorile pana la maximum ${MAX_GENERATED_VARIANTS} sau adauga manual doar variantele reale.`,'warning'); return; } const existingKeys=getExistingVariantKeys(); let addedCount=0; combinations.forEach(combo=>{ const key=buildVariantKeyFromMeta(combo); if(existingKeys.includes(key)) return; appendVariantCard({sku:'',price:'',stock:'',is_active:1,attributes_meta:combo}); addedCount++; }); if(!addedCount){ setVariantHelper('Nu exista combinatii noi de adaugat. Variantele selectate sunt deja in lista.','warning'); return; } setVariantHelper(`Am adaugat ${addedCount} combinatii. Completeaza pretul, stocul si SKU-ul pentru fiecare varianta.`,'success'); updateTotalStockFromVariants(); updateFormGuidance(); }
categorySelect.addEventListener('change',()=>{ refreshSubcategories(); renderAttributeSections([]); attributesPlaceholder.classList.remove('hidden'); attributesPlaceholder.textContent='Alege mai intai categoria finala pentru a vedea atributele.'; variantsRows.innerHTML=''; variantsTableWrap.classList.add('hidden'); toggleBaseStock(); updateTotalStockFromVariants(); updateFormGuidance(); });
subcategorySelect.addEventListener('change',()=>{ variantsRows.innerHTML=''; variantsTableWrap.classList.add('hidden'); loadCategoryAttributes(); updateFormGuidance(); });
if(hasVariantsToggle){ hasVariantsToggle.addEventListener('change',()=>{ if(!hasVariantsToggle.checked){ variantsRows.innerHTML=''; variantsTableWrap.classList.add('hidden'); } syncProductModeFromToggle(); updateVariantModeUI(); syncVariantControls(); syncVariantsIntent(); toggleBaseStock(); updateTotalStockFromVariants(); updateFormGuidance(); }); }
if(productModeSimple){ productModeSimple.addEventListener('change',()=>{ if(!productModeSimple.checked||!hasVariantsToggle) return; hasVariantsToggle.checked=false; hasVariantsToggle.dispatchEvent(new Event('change')); }); }
if(productModeVariants){ productModeVariants.addEventListener('change',()=>{ if(!productModeVariants.checked||!hasVariantsToggle) return; hasVariantsToggle.checked=true; hasVariantsToggle.dispatchEvent(new Event('change')); }); }
generateVariantsBtn.addEventListener('click',addVariantsByPrimaryAttribute);
addVariantRowBtn.addEventListener('click',()=>{ const selection=collectSelectedVariantCombos(); if(selection.error){ setVariantHelper(selection.error,'danger'); return; } if(!selection.combos.length){ setVariantHelper('Selecteaza mai intai combinatia pe care vrei sa o adaugi manual.','danger'); return; } if(selection.combos.length>1){ setVariantHelper('Ai selectat mai multe combinatii. Pentru toate foloseste Genereaza combinatii, iar pentru una singura lasa o singura selectie pe fiecare atribut.','warning'); return; } appendVariantCard({sku:'',price:'',stock:'',is_active:1,attributes_meta:selection.combos[0]}); setVariantHelper('Ai adaugat o singura varianta pe baza selectiei curente. Completeaza pretul si stocul.','info'); });
clearVariantsBtn.addEventListener('click',()=>{ variantsRows.innerHTML=''; updateVariantModeUI(); syncVariantsIntent(); toggleBaseStock(); updateTotalStockFromVariants(); setVariantHelper('Lista variantelor a fost golita. Poti genera din nou doar combinatiile reale.','warning'); updateFormGuidance(); });
variantsRows.addEventListener('click',event=>{ if(!event.target.classList.contains('remove-variant-btn')) return; const card=event.target.closest('[data-variant-card]'); if(card){ card.remove(); reindexVariantCards(); syncVariantsIntent(); toggleBaseStock(); updateTotalStockFromVariants(); loadSizesForSelectedColor(); updateFormGuidance(); } });
variantsRows.addEventListener('input',event=>{ if(event.target.classList.contains('variant-stock-input')||event.target.classList.contains('variant-price-input')||event.target.name?.includes('[sku]')){ updateTotalStockFromVariants(); updateFormGuidance(); } });
dynamicAttributes.addEventListener('input',updateFormGuidance); dynamicAttributes.addEventListener('change',updateFormGuidance);
document.addEventListener('click',event=>{ if(!event.target.classList.contains('add-custom-variant')) return; const attributeId=event.target.dataset.attributeId,block=document.querySelector(`[data-variant-attribute-block="${attributeId}"]`); if(!block) return; const input=block.querySelector('.custom-variant-input'),value=(input.value||'').trim(); if(!value) return; const list=block.querySelector('.variant-checkbox-list'),primaryAttr=getPrimaryVariantAttribute(),isPrimary=primaryAttr&&String(primaryAttr.id)===String(attributeId),wrapper=document.createElement('label'); wrapper.className='inline-flex items-center gap-2 rounded-xl border border-gray-300 px-3 py-2 text-sm text-gray-700 hover:bg-gray-50'; wrapper.innerHTML=`<input type="${isPrimary?'radio':'checkbox'}" name="variant_attr_${attributeId}" class="variant-checkbox" data-attribute-id="${attributeId}" data-option-id="" data-label="${escapeHtml(value)}" data-custom="1" checked><span>${escapeHtml(value)}</span>`; list.appendChild(wrapper); input.value=''; setVariantHelper(`Am adaugat valoarea noua "${value}".`,'success'); if(isPrimary) loadSizesForSelectedColor(); });
document.addEventListener('change',event=>{ const primaryAttr=getPrimaryVariantAttribute(); if(primaryAttr&&event.target.matches(`input[name="variant_attr_${primaryAttr.id}"]`)) loadSizesForSelectedColor(); if(event.target.classList.contains('variant-checkbox')) updateFormGuidance(); });
imageInput.addEventListener('change',event=>{ const file=event.target.files?.[0]; if(!file){ imagePreview.src=''; imagePreviewWrap.classList.add('hidden'); updateFormGuidance(); return; } const reader=new FileReader(); reader.onload=readerEvent=>{ imagePreview.src=readerEvent.target.result; imagePreviewWrap.classList.remove('hidden'); }; reader.readAsDataURL(file); updateFormGuidance(); });
galleryInput.addEventListener('change',event=>{ const files=Array.from(event.target.files||[]); if(!files.length){ renderGalleryPreview(); updateFormGuidance(); return; } mergeGalleryFiles(files); if(files.length>GALLERY_LIMIT||selectedGalleryFiles.length>=GALLERY_LIMIT) setAssistantState('warning','Galeria are limita maxima',`Poti avea maximum ${GALLERY_LIMIT} imagini selectate simultan.`,['Pozele noi se adauga la lista existenta.','Scoate o imagine din preview daca vrei sa faci loc alteia.']); updateFormGuidance(); });
galleryPreviewGrid?.addEventListener('click',event=>{ const button=event.target.closest('.remove-gallery-file'); if(!button) return; removeGalleryFile(Number(button.dataset.galleryIndex)); updateFormGuidance(); });
productForm?.addEventListener('submit',event=>{ syncVariantsIntent(); const {missing}=collectFormState(); if(missing.length){ event.preventDefault(); setAssistantState('danger','Formularul nu este gata','Am oprit salvarea ca sa nu trimitem un produs incomplet sau greu de filtrat.',missing.slice(0,6)); updateReadinessPanel(missing,[]); document.getElementById('step-1')?.scrollIntoView({behavior:'smooth',block:'start'}); return; } if(submitProductBtn){ submitProductBtn.disabled=true; submitProductBtn.classList.add('opacity-70','cursor-not-allowed'); } });
refreshSubcategories(selectedSub); if(selectedSub) loadCategoryAttributes(); else updateFormGuidance(); syncProductModeFromToggle(); updateVariantModeUI(); syncVariantControls(); syncVariantsIntent(); toggleBaseStock(); updateTotalStockFromVariants(); updateGallerySelectionText(); renderGalleryPreview(); updateFormGuidance();
</script>


